import React, { useState } from 'react';
import { events } from '../../data/events';
import EventCard from '../../components/EventCard/EventCard';
import './Events.css';

const CATEGORIES = ['All', 'Runway Show', 'Bridal Show', 'Street Show', 'Gala', 'Ethnic Show'];

function Events() {
  const [activeCategory, setActiveCategory] = useState('All');
  const [search, setSearch] = useState('');

  const filtered = events.filter((e) => {
    const matchCat = activeCategory === 'All' || e.category === activeCategory;
    const matchSearch =
      e.title.toLowerCase().includes(search.toLowerCase()) ||
      e.location.toLowerCase().includes(search.toLowerCase());
    return matchCat && matchSearch;
  });

  return (
    <div className="events-page">
      {/* Hero */}
      <div className="page-hero">
        <h1>All Events</h1>
        <p>Browse and book seats for our exclusive modeling events</p>
      </div>

      <div className="container events-page__body">
        {/* Search & Filter */}
        <div className="events-page__controls">
          <input
            type="text"
            placeholder="🔍  Search by event name or city..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="events-page__search"
          />
          <div className="events-page__filters">
            {CATEGORIES.map((cat) => (
              <button
                key={cat}
                className={`filter-btn ${activeCategory === cat ? 'active' : ''}`}
                onClick={() => setActiveCategory(cat)}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        {/* Results count */}
        <p className="events-page__count">
          Showing <strong>{filtered.length}</strong> event{filtered.length !== 1 ? 's' : ''}
        </p>

        {/* Grid */}
        {filtered.length > 0 ? (
          <div className="events-grid">
            {filtered.map((event) => (
              <EventCard key={event.id} event={event} />
            ))}
          </div>
        ) : (
          <div className="events-page__empty">
            <p>🎭 No events found matching your criteria.</p>
            <button className="btn-outline" onClick={() => { setActiveCategory('All'); setSearch(''); }}>
              Clear Filters
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

export default Events;
